"use client";

import { Menu, X } from "lucide-react";
import Link from "next/link";
import { useState } from "react";
import { siteConfig } from "@/lib/site";

export function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <header className="sticky top-0 z-50 border-b border-white/10 bg-brand-navy/95 text-white backdrop-blur">
      <nav className="container-page flex h-[var(--header-height)] items-center justify-between">
        <Link href="/" className="flex items-center gap-3" aria-label="Metodo Aristi inicio">
          <span className="grid h-11 w-11 place-items-center rounded bg-brand-green font-display text-3xl leading-none text-white">
            A
          </span>
          <span className="font-display text-3xl tracking-normal">Metodo Aristi</span>
        </Link>

        <div className="hidden items-center gap-8 md:flex">
          {siteConfig.navItems.map((item) => (
            <Link
              key={item.href}
              href={item.href}
              className="text-sm font-semibold uppercase tracking-wide text-white/78 transition hover:text-brand-gold"
            >
              {item.label}
            </Link>
          ))}
        </div>

        <button
          type="button"
          className="grid h-11 w-11 place-items-center rounded border border-white/15 md:hidden"
          aria-label={isOpen ? "Cerrar menu" : "Abrir menu"}
          aria-expanded={isOpen}
          onClick={() => setIsOpen((value) => !value)}
        >
          {isOpen ? <X size={22} /> : <Menu size={22} />}
        </button>
      </nav>

      {isOpen ? (
        <div className="border-t border-white/10 bg-brand-navy md:hidden">
          <div className="container-page grid gap-1 py-4">
            {siteConfig.navItems.map((item) => (
              <Link
                key={item.href}
                href={item.href}
                className="rounded px-3 py-3 text-sm font-semibold uppercase tracking-wide text-white/80 hover:bg-white/10 hover:text-brand-gold"
                onClick={() => setIsOpen(false)}
              >
                {item.label}
              </Link>
            ))}
          </div>
        </div>
      ) : null}
    </header>
  );
}
